from pydantic_ai import Agent, tool
from vex import Guardrail, ResultValidator

@Guardrail(name="phi_detector")
def validate_phi_free(output: str) -> bool:
    import re
    phi_patterns = [
        r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
        r'\b[A-Z][a-z]+\s[A-Z][a-z]+\b',  # Full names
        r'\b\d{3}-\d{3}-\d{4}\b'   # Phone
    ]
    return not any(re.search(pattern, output) for pattern in phi_patterns)

class HealthcareAgent(Agent):
    result_validators = [ResultValidator(guardrail="phi_detector")]

    @tool
    def summarize_patient_chart(self, mrn: str) -> str:
        """Generate PHI-free patient summary"""
        return "Patient stable, vitals normal, no PHI included."

from pydantic_ai import Agent, tool
from vex import Guardrail, audit_log

class CompliantHealthcareAgent(Agent):
    @Guardrail(name="decision_audit")
    def validate_decision_rationale(self, output: dict) -> bool:
        required_fields = ["decision", "rationale", "confidence", "timestamp"]
        return all(field in output for field in required_fields) and output["confidence"] > 0.8

    result_validators = [ResultValidator(guardrail="decision_audit")]

    @tool
    def recommend_treatment(self, symptoms: str, vitals: dict) -> dict:
        decision = {
            "decision": "Monitor closely",
            "rationale": "Stable vitals, mild symptoms",
            "confidence": 0.92,
            "timestamp": "2024-01-15T10:30:00Z"
        }
        audit_log(decision, agent_id="healthcare-agent-1")
        return decision
